import java.io.*;import java.util.*;public class Solution{public static void main(String[]a)throws Exception{Scanner sc=new Scanner(System.in);int T=sc.nextInt();String dirs="NESW";int[] dr={-1,0,1,0},dc={0,1,0,-1};StringBuilder out=new StringBuilder();for(int tc=0;tc<T;tc++){int R=sc.nextInt(),C=sc.nextInt(),r=sc.nextInt(),c=sc.nextInt();char d=sc.next().charAt(0);String cmd=sc.next();int di=dirs.indexOf(d);for(char ch:cmd.toCharArray()){if(ch=='L')di=(di+3)%4;else if(ch=='R')di=(di+1)%4;else{int nr=r+dr[di],nc=c+dc[di];if(nr>=1&&nr<=R&&nc>=1&&nc<=C){r=nr;c=nc;}}}if(tc>0)out.append('\n');out.append("Final = (").append(r).append(", ").append(c).append(", ").append(dirs.charAt(di)).append(")");}System.out.print(out);}}